327→    // One-time wormhole fetch on mount
328→    useEffect(() => {
329→        let cancelled = false;
330→
331→        const fetchWormholes = async () => {
332→            try {
333→                const { data, error } = await supabase.rpc('find_wormhole_pairs', {
334→                    similarity_threshold: 0.7,
